import{_ as r,c as o,o as l,a5 as t,j as a}from"./chunks/framework.Dtwt352Q.js";const b=JSON.parse('{"title":"v1.2.8：Claude 4.6 思考模式、MCP 调用可视化","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.8.md","filePath":"changelog/v1.2.8.md","lastUpdated":1772014034000}'),n={name:"changelog/v1.2.8.md"};function d(s,e,i,h,c,p){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="v1-2-8-claude-4-6-思考模式、mcp-调用可视化" tabindex="-1">v1.2.8：Claude 4.6 思考模式、MCP 调用可视化 <a class="header-anchor" href="#v1-2-8-claude-4-6-思考模式、mcp-调用可视化" aria-label="Permalink to “v1.2.8：Claude 4.6 思考模式、MCP 调用可视化”">​</a></h1><p><strong>发布日期</strong>：2026-02-19</p><p>这个版本带来了<strong>Claude Sonnet 4.6 的自适应思考支持</strong>，以及 TUI 中<strong>自定义工具和 MCP 调用的可视化展示</strong>。</p><h2 id="🎯-一句话总结" tabindex="-1">🎯 一句话总结 <a class="header-anchor" href="#🎯-一句话总结" aria-label="Permalink to “🎯 一句话总结”">​</a></h2><p>支持 Claude 4.6 自适应思考；MCP 工具调用结果现在可见且可折叠；桌面端黑屏问题已修复。</p><hr><h2 id="✨-新功能" tabindex="-1">✨ 新功能 <a class="header-anchor" href="#✨-新功能" aria-label="Permalink to “✨ 新功能”">​</a></h2><h3 id="🧠-claude-sonnet-4-6-自适应思考" tabindex="-1">🧠 Claude Sonnet 4.6 自适应思考 <a class="header-anchor" href="#🧠-claude-sonnet-4-6-自适应思考" aria-label="Permalink to “🧠 Claude Sonnet 4.6 自适应思考”">​</a></h3><p>为 Claude Sonnet 4.6 模型添加了<strong>自适应思考（adaptive thinking）</strong>支持。</p><p><strong>怎么用</strong>：使用 Claude Sonnet 4.6 时，模型会根据任务复杂度自动调整思考深度。</p><p><strong>对谁有价值</strong>：使用 Claude Sonnet 4.6 的用户，特别是处理复杂任务时。</p><hr><h3 id="📊-mcp-调用结果可视化-tui" tabindex="-1">📊 MCP 调用结果可视化（TUI） <a class="header-anchor" href="#📊-mcp-调用结果可视化-tui" aria-label="Permalink to “📊 MCP 调用结果可视化（TUI）”">​</a></h3><p>在 TUI 中，<strong>自定义工具和 MCP 调用的响应现在可见且可折叠</strong>。</p><p><strong>怎么用</strong>：当 AI 调用 MCP 工具时，你可以在对话中看到调用结果，点击可展开/折叠。</p><p><strong>对谁有价值</strong>：使用 MCP 扩展的用户，方便调试和了解工具执行情况。</p><hr><h2 id="🐛-问题修复" tabindex="-1">🐛 问题修复 <a class="header-anchor" href="#🐛-问题修复" aria-label="Permalink to “🐛 问题修复”">​</a></h2><h3 id="桌面端黑屏问题" tabindex="-1">桌面端黑屏问题 <a class="header-anchor" href="#桌面端黑屏问题" aria-label="Permalink to “桌面端黑屏问题”">​</a></h3><p>修复了使用 sidecar 服务器时桌面端启动后出现黑屏的问题。</p><h3 id="todos-清理" tabindex="-1">Todos 清理 <a class="header-anchor" href="#todos-清理" aria-label="Permalink to “Todos 清理”">​</a></h3><p>中止（abort）操作时现在会正确清除 todos 列表。</p><hr><h2 id="📊-要不要升级" tabindex="-1">📊 要不要升级？ <a class="header-anchor" href="#📊-要不要升级" aria-label="Permalink to “📊 要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 Claude Sonnet 4.6</td><td>✅ 强烈推荐</td></tr><tr><td>使用 MCP 工具</td><td>✅ 推荐</td></tr><tr><td>桌面端有黑屏问题</td><td>✅ 推荐</td></tr><tr><td>一切正常</td><td>⚪ 可选升级</td></tr></tbody></table><hr><h2 id="⬆️-升级命令" tabindex="-1">⬆️ 升级命令 <a class="header-anchor" href="#⬆️-升级命令" aria-label="Permalink to “⬆️ 升级命令”">​</a></h2>',27),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="📋-技术细节" tabindex="-1">📋 技术细节 <a class="header-anchor" href="#📋-技术细节" aria-label="Permalink to “📋 技术细节”">​</a></h2><details><summary>点击展开原始 Release Notes</summary><h2 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h2><ul><li>Support adaptive thinking for Claude Sonnet 4.6 (@tctev)</li></ul><h2 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h2><ul><li>Add custom tool and MCP call responses that are visible and collapsible (@yanosh-k)</li></ul><h2 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h2><ul><li>Black screen on launch with sidecar server fixed</li><li>Clear todos on abort</li></ul><p><strong>Thank you to 2 community contributors:</strong></p><ul><li>@yanosh-k: feat(tui): add custom tool and mcp call responses visible and collapsable</li><li>@tctev: feat(opencode): support adaptive thinking for claude sonnet 4.6</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=r(n,[["render",d]]);export{b as __pageData,m as default};
